import EmptyDataView from './EmptyDataView'
import React, { useEffect, useState } from 'react'
import { containerConstantsService } from '../../utils/containerconstants/ContainerConstants';
import BreadCrumb from '../commoncomponent/breadcrumb/bread_crumb';
import LabelTemplateStyle from './LabelTemplateStyle.js'
import { Card, Table, Popover, Button, Spin, Space, Input, Tag, Dropdown, Menu, Modal, Row, Col, Select } from 'antd';
import { PlusOutlined } from '@ant-design/icons';
import MoreOutlined from '../commoncomponent/CustomIcons/MoreOutlined';
import HtmlEditor from './HtmlEditor';
import { PAGE_SIZE, STATUS, DATA_INDEX, TEMPLATE_MODAL_TYPE, OPERATIONS } from '../../utils/constants';
import CustomModal from './CustomModal';
import { saveLabelTemplatePartyMapping, fetchAllPartyMaster, fetchLabelTemplateList, activateDeactivateLabelTemplate, deleteLabelTemplate, fetchLabelPartyMapping } from "../APIConfig/LabelTemplateAction";
import { notifyResponseMessage } from '../commoncomponent/NotificationComponent/notifyResponseMessage';
import CustomPagination from '../commoncomponent/CustomPagination/CustomPagination'
import { SearchOutlined, DownOutlined } from '@ant-design/icons';
import { toLower, toUpper, upperFirst, isEmpty } from 'lodash';
import { useStore } from '../hook-store/store';
import {getBasePath} from '../commoncomponent/BasePath';

const containerConstants = containerConstantsService.getInstance();

const LabelTemplate = (props) => {
    const store = useStore(true)[0];
    const [showModalDialog, setShowModalDialog] = useState(false);
    const [showPopover, setShowPopover] = useState({ visible: false, key: null, leftTab: null });
    const [pageDetail, setPageDetail] = useState({ current: 0, pageSize: 10 });
    const [paginationDetails,setPaginationDetails] =  useState({ totalElements: 0 , numberOfElements: 0, pageSizeText: PAGE_SIZE.PAGE_10});
    const [showEditor, setShowEditor] = useState({ visible: false });
    const [showTable, setShowTable] = useState(true);
    const [statusUpdate, setStatusUpdate] = useState(false);
    const [labelTemplateList, setLabelTemplateList] = useState([]);
    const [showConfirmModalDialog, setShowConfirmModalDialog] = useState({ visible: false, okText: '', title: '' });
    const [showLoading,setShowLoading] = useState(false);
    const [partyMasterCodeSet, setPartyMasterCodeSet] = useState(new Set());
    const [partyMasterCodeOptios, setPartyMasterCodeOptios] = useState([]);
    const [avaliablePartyMasterCodeOptios, setAvaliablePartyMasterCodeOptios] = useState([]);
    const [searchfilters, setSearchfilters] =  useState('');
    const searchedColumn  = useState()[0];
    const searchText  = useState()[0];
    const searchInput = useState()[0];
    const [ linkedPartyCodes, setLinkedPartyCodes ] = useState([]);
    const [ templateCodeForAddParty, setTemplateCodeForAddParty ] = useState(false);
    const [showModalDialogLinkParty, setShowModalDialogLinkParty] = useState(false);
    const [ basePath, setBasePath ]  = useState(''); 

    const getColumnSearchProps = ( dataValue , dataIndex) => ({

        filterDropdown: ({ setSelectedKeys, selectedKeys, confirm, clearFilters }) => (
          <div style={{ padding: 8 }}>
            <Input
              placeholder={`Search ${dataValue}`}
              value={searchfilters}
              onChange={e => {
                setSearchfilters( e.target.value );
                return e.target.value ;

              }}
              onPressEnter={() => handleSearch(selectedKeys, confirm, dataIndex)}
              style={{ width: 188, marginBottom: 8, display: 'block' }}
            />
            <Space>
              <Button
                type="primary"
                onClick={() => handleSearch(selectedKeys, confirm, dataIndex)}
                icon={<SearchOutlined />}
                size="small"
                style={{ width: 90 }}
              >
                {containerConstants.formatString(containerConstants.SEARCH)}
              </Button>
              <Button onClick={() => handleReset(dataIndex)} size="small" style={{ width: 90 }}>
              {containerConstants.formatString(containerConstants.RESET)}
              </Button>

            </Space>
          </div>
        ),
        filterIcon: filtered => <SearchOutlined style={{ fontSize : '14px', marginRight:'10px', color: '#727272' }} />,
        onFilter: (value, record) =>  record[dataIndex]
            ? record[dataIndex].toString().toLowerCase().includes(value.toLowerCase())
            : ''
        ,
        onFilterDropdownVisibleChange: visible => {
          if (visible) {
            setTimeout(() => searchInput && searchInput.select(), 100);
          }
        },
        render: text =>
            searchedColumn === dataIndex ?
              searchText :
              text

    });

    const urlList =
        [
            {
                url: basePath +'/v2/label_generation/v2/settings',
                heading: containerConstants.formatString(containerConstants.SETTINGS),
            },
            {
                url: basePath +'/v2/label_generation/settings',
                heading: containerConstants.formatString(containerConstants.ADD_ORDER_AND_GENERATE_LABEL)
            },
            {
                url: basePath +'/v2/label_generation/label_templates',
                heading:
                    (<>
                        <span>{containerConstants.formatString(containerConstants.LABEL_TEMPLATES)}</span>
                    </>)
            }
        ];

    const urlListForNewSetting =
    [
        {
            url: '/v2/new_settings/label_generation/settings',
            heading: containerConstants.formatString(containerConstants.ADD_ORDER_AND_GENERATE_LABEL)
        },
        {
            url: '/v2/new_settings/label_generation/label_templates',
            heading:
                (<>
                    <span>{containerConstants.formatString(containerConstants.LABEL_TEMPLATES)}</span>
                </>)
        }
    ];
        

    const getAllPartyMaster = async () => {
        await fetchAllPartyMaster()
            .then(response => {
                if (response && response.status === 200) {
                    let partyMasterCodeSet1  = new Set();
                    let partyMasterCodeOption  = [];
                    const partyMasterList = response.data?.data;
                    partyMasterList && partyMasterList.map(partyMaster => {partyMaster
                        &&  partyMasterCodeSet1.add(partyMaster.merchantCode);
                        partyMaster && partyMasterCodeOption.push({label  :partyMaster.merchantCode, value:partyMaster.merchantCode });
                    })
                    setPartyMasterCodeSet(partyMasterCodeSet1);
                    setPartyMasterCodeOptios(partyMasterCodeOption);

                }
            })
            .catch(error => {

            });
    }

    const getAllTemplate = async ( ) => {
        setShowLoading(true);
        await fetchLabelTemplateList(pageDetail.current, pageDetail.pageSize, searchfilters )
            .then(response => {
                setShowLoading(false);
                if (response && response.status === 'Success') {
                    if(response.data ){
                        const labelTemplateListRes = response.data.content;
                        if (!isEmpty(labelTemplateListRes)) {
                            setLabelTemplateList(labelTemplateListRes)
                            setShowTable(true);
                            setPaginationDetails({
                                totalElements: response.data.totalElements,
                                numberOfElements : response.data.numberOfElements,
                                pageSizeText: paginationDetails.pageSizeText
                            });
                        }
                        else {
                            if(response.data.totalElements > 0 && pageDetail.current > 0 ){
                                setPageDetail({current:pageDetail.current-1, pageSize:pageDetail.pageSize});
                                setShowTable(true);
                            }else{
                                setShowTable(false)
                                setLabelTemplateList(labelTemplateListRes);
                            }
                        }
                    }else{
                        setShowTable(false)
                    }
                }
            })
            .catch(error => {
                setShowLoading(false);

            });
    }

    useEffect(() => {
        setBasePath(getBasePath(props, store));
        document.title = containerConstants.formatString(containerConstants.LABEL_TEMPLATES);
        const fetchParty = async() =>{
            if(partyMasterCodeSet.size === 0 ){
                await getAllPartyMaster();
            }
        }

	fetchParty();
        const fetchTemplate  = async() =>{
            await getAllTemplate();
        }  
        fetchTemplate();

    }, [showTable, statusUpdate,pageDetail, showEditor, partyMasterCodeSet.size]);

    const updateTemplateStatus = async (record, publishTemplateReqObj) => {

        const status = (record?.status === STATUS.ACTIVE) ? false : true;

        const templateUpdateStatusReqObj = {
            [DATA_INDEX.TEMPLATE_ID]: record?.id,
            [DATA_INDEX.IS_ACTIVE]: status,
        };

        let responseStatus = '';
        let responseMessage = publishTemplateReqObj === undefined ?containerConstants.formatString(containerConstants.STATUS_UPDATE_SUCCESSFULLY): containerConstants.formatString(containerConstants.TEMPLATE_SAVED_SUCCESSFULLY) ;

        try {
            setShowLoading(true);
            const templateResponse = await activateDeactivateLabelTemplate(record ? templateUpdateStatusReqObj : publishTemplateReqObj);
            setShowLoading(false);
            if (templateResponse && templateResponse.status === 200) {
                responseStatus = templateResponse.data?.status;
                responseMessage =  toUpper(responseStatus) === STATUS.SUCCESS ? responseMessage : templateResponse.data?.message;
            }
        }
        catch (error) {
            setShowLoading(false);

        }


        if (toUpper(responseStatus) === STATUS.SUCCESS) {
            notifyResponseMessage(STATUS.SUCCESS, responseMessage);
            setShowPopover({ visible: false, key: null, leftTab: null });
            setStatusUpdate(prev => !prev)
            return responseStatus;
        }else{
            notifyResponseMessage(STATUS.ERROR, responseMessage);
        }
    }

    const deleteTemplate = (id) => {
        setShowLoading(true);
        deleteLabelTemplate(id)
            .then(response => {
                setShowLoading(false);
                if (response.status === 200) {
                    if (toUpper(response.data?.status) === STATUS.SUCCESS) {
                        notifyResponseMessage(STATUS.SUCCESS, response?.data?.message);
                        setStatusUpdate(prev => !prev);
                        setShowTable(true);
                        getAllTemplate();

                    }else{
                        notifyResponseMessage(STATUS.ERROR, response?.data?.message);

                    }

                }
            })
            .catch(error => {
                setShowLoading(false);

            });
    }

    const clickPopoverEditHandler = (dataObject) => {
        setShowEditor({
            visible: true,
            operationType: OPERATIONS.EDIT,
            [DATA_INDEX.TEMPLATE_ID]: dataObject.id,
            [DATA_INDEX.TEMPLATE_STATUS]: dataObject.status,
            [DATA_INDEX.TEMPLATE_SCRIPT]: dataObject.script,
            [DATA_INDEX.TEMPLATE_NAME]: dataObject.name
        });
        setShowPopover({ visible: false, key: null, leftTab: null });
    }

    const templatePopoverIconClasses = 'template-popover-icon flex align-center justify-center pointer mr10';

    const CustomCell = ({ children, record, ...restProps }) => {
        return (
            <td {...restProps}>
                {record ?
                    (<div className='flex align-center'>
                        <Popover
                            // visible={record?.id === showPopover.key && showPopover.visible}
                            // onVisibleChange={(visible) => setShowPopover(visible ? { visible: visible, key: record.id } : {})}
                            id='label_template_table_popover'
                            placement="bottomLeft"
                            content={
                                <div>
                                    <p id='label_template_table_popover_content'
                                        className = { store.fromFCR ? '' : store.showCustom  ? 'non_selectable' : '' }
                                        onClick={() => ( store.fromFCR || ! store.showCustom ) && clickPopoverEditHandler(record)}>
                                        {containerConstants.formatString(containerConstants.EDIT)}
                                    </p>
                                    <p id='label_template_table_popover_content'
                                        className = { store.fromFCR ? '' : store.showCustom  ? 'non_selectable' : '' }
                                        onClick={() => {
                                            ( store.fromFCR || ! store.showCustom ) && setShowConfirmModalDialog({
                                                visible: true,
                                                okText: containerConstants.formatString(record.status === STATUS.ACTIVE ? containerConstants.INACTIVE : record.status === STATUS.DRAFT ? containerConstants.PUBLISH : containerConstants.ACTIVE),
                                                title: containerConstants.formatString(containerConstants.STATUS_UPDATE) + '?',
                                                description: containerConstants.formatString(containerConstants.CONFIRM_DESCRIPTION),
                                                record: record
                                            });
                                            ( store.fromFCR || ! store.showCustom ) && setShowPopover({ visible: false, key: null });
                                        }}
                                    >
                                        {containerConstants.formatString(record.status === STATUS.ACTIVE ? containerConstants.INACTIVE : record.status === STATUS.DRAFT ? containerConstants.PUBLISH : containerConstants.ACTIVE)}
                                    </p>
                                    <p
                                        className = { store.fromFCR ? '' : store.showCustom  ? 'non_selectable' : '' }
                                        onClick={() => {
                                            ( store.fromFCR || ! store.showCustom )  && setShowConfirmModalDialog({
                                                visible: true,
                                                okText: containerConstants.formatString(containerConstants.DELETE),
                                                title: containerConstants.formatString(containerConstants.DELETE) + '?',
                                                description: containerConstants.formatString(containerConstants.DELETE_DESCRIPTION),
                                                rowId: record.id
                                            });
                                            ( store.fromFCR || ! store.showCustom ) && setShowPopover({ visible: false, key: null });
                                        }}
                                    >
                                        {containerConstants.formatString(containerConstants.DELETE)}
                                    </p>
                                </div>}
                            trigger="click">
                            <div className={((record?.id === showPopover.key) ? templatePopoverIconClasses.concat(' ', 'selected bg-primary') : templatePopoverIconClasses)}>
                                <MoreOutlined color={(record?.id === showPopover.key) ? '#FFFFFF' : '#323232'} />
                            </div>
                        </Popover>
                        <span style={{ marginLeft: '12px' }} className='fw400 fs12 lh18'>{children}</span>
                    </div>)
                    : children}
            </td>
        );
    }

    const handlePageChange = (val) => {
        setPageDetail({current:val-1, pageSize:pageDetail.pageSize});
    }

    const handlePgaeSizeChange = (val) => {
        let pageSize = 10;
        let pageSizeTxt = PAGE_SIZE.PAGE_10;
        switch(val){
            case PAGE_SIZE.PAGE_10 :
                pageSize = 10;
                pageSizeTxt = PAGE_SIZE.PAGE_10;
                break;
            case PAGE_SIZE.PAGE_20 :
                pageSize = 20;
                pageSizeTxt = PAGE_SIZE.PAGE_20;
                break;
            case PAGE_SIZE.PAGE_50 :
                pageSize = 50;
                pageSizeTxt = PAGE_SIZE.PAGE_50;
                break;
            case PAGE_SIZE.PAGE_100 :
                pageSize = 100;
                pageSizeTxt = PAGE_SIZE.PAGE_100;
                break;
            default:
                break;
        }

        setPaginationDetails({
            totalElements: paginationDetails.totalElements,
            numberOfElements : paginationDetails.numberOfElements,
            pageSizeText: pageSizeTxt
        });
        setPageDetail({current:0, pageSize:pageSize});
    }

    const getMenuForDropDown = (partyCode) =>{

        const menus = partyCode && partyCode.split(",").map((data) => {

            return (
              <Menu.Item key={data} >
                {data}
              </Menu.Item>
            )
        });
        const menu = () => {
            return (
              <Menu >
                {menus}
              </Menu>
            )
        }
        return <Dropdown overlay={menu} placement="bottomLeft">
                    <DownOutlined
                        style = {{paddingRight: '8px', paddingLeft: '5px'}}
                        color='#727272'/>
                </Dropdown>
    }

    const closeLinkPartyDialog = () => {
        setTemplateCodeForAddParty(null);
        setLinkedPartyCodes([]);
        setShowModalDialogLinkParty(false);

    }

    const openLinkTemplateBox = (data) => {
        data && data.partyCode && data.partyCode.split(",").length > 0 && setLinkedPartyCodes(data.partyCode.split(","))
        setShowLoading(true);
        fetchLabelPartyMapping()
        .then(response => {
            setShowLoading(false);
            if (response && response.status === 200 && response.data && response.data.status === 'Success') {
                const mappedMerchantCode = new Set();
                response.data.data && Object.entries(response.data.data).map(item => {
                    if(item[0] !== data.templateCode){
                        if(item[1].includes(",")){
                            item[1].split(",").forEach(merchantCode=> mappedMerchantCode.add(merchantCode));
                        }else{
                            mappedMerchantCode.add(item[1]);
                        }
                    }
                })
                let availableMerchantCode = [] ;
                partyMasterCodeOptios.forEach( merchantCode => {

                 if(!mappedMerchantCode.has(merchantCode.value)){
                    availableMerchantCode.push(
                        {label :merchantCode.value, value:merchantCode.value }
                        );
                 }
                });
                setAvaliablePartyMasterCodeOptios(availableMerchantCode);
        setTemplateCodeForAddParty(data.templateCode);
        setShowModalDialogLinkParty(true);
    }
        })
        .catch(error => {
            setShowLoading(false);
        });
    }

    const saveLinkedParty = () => {
        setShowLoading(true);
        saveLabelTemplatePartyMapping( linkedPartyCodes, templateCodeForAddParty )
            .then(response => {
                setShowLoading(false);
                if (response && response.status === 200 && response.data && response.data.status === 'Success') {
                    notifyResponseMessage(STATUS.SUCCESS,containerConstants.formatString(containerConstants.SUCCESSFULLY_UPDATED));
                    closeLinkPartyDialog();
                    getAllTemplate();
                }else{
                    notifyResponseMessage(STATUS.ERROR,response && response.data && response.data.message? response.data.message : containerConstants.formatString(containerConstants.SOMETHING_WENT_WRONG));
                }
            })
            .catch(error => {
                setShowLoading(false);
                notifyResponseMessage(STATUS.ERROR,error);
            });
    }


    const LABEL_TEMPLATE_TABLE_HEADER = [
        {
            title: <div className='font-family-weight-500 fs10 lh16 ml26'>{containerConstants.formatString(containerConstants.NAME)}</div>,
            dataIndex: DATA_INDEX.NAME,
            width: '16%',
            ...getColumnSearchProps(DATA_INDEX.NAME,DATA_INDEX.NAME, DATA_INDEX.NAME),
            onCell: (record, rowIndex) => ({ record, rowIndex }),

        },
        {
            title: <div className='font-family-weight-500 fs10 lh16'>{containerConstants.formatString(containerConstants.TEMPLATE_CODE)}</div>,
            dataIndex: DATA_INDEX.TEMPLATE_CODE,
            width: '16%',
            key: '1',
            render: text => <div className='fw400 fs12 lh18'>{text}</div>
        },
        {
            title: <div className='font-family-weight-500 fs10 lh16'>{containerConstants.formatString(containerConstants.CREATED_ON)}</div>,
            dataIndex: DATA_INDEX.CREATED_AT,
            width: '20%',
            key: '3',
            render: text => <div className='fw400 fs12 lh18'>{text}</div>
        },

        {
            title: <div className='font-family-weight-500 fs10 lh16'>{containerConstants.formatString(containerConstants.LAST_MODIFIED_ON)}</div>,
            dataIndex: DATA_INDEX.LAST_MODIFIED_AT,
            width: '20%',
            key: '4',
            render: text => <div className='fw400 fs12 lh18'>{text}</div>
        },
        {
            title: <div className='font-family-weight-500 fs10 lh16'>{containerConstants.formatString(containerConstants.PAGE_SIZE)}</div>,
            dataIndex: DATA_INDEX.PAGE_SIZE,
            width: '20%',
            key: '4',
            render: text => <div className='fw400 fs12 lh18'>{text}</div>
        },
        {
            title: <div className='font-family-weight-500 fs10 lh16'>{containerConstants.formatString(containerConstants.STATUS)}</div>,
            dataIndex: DATA_INDEX.STATUS,
             width: '10%',
             key: '6',
            render: text => <Tag className={'font-family-weight-500 fs10 lh14 br4' + (toUpper(text) === STATUS.ACTIVE ? ' status-tag-active' : ' status-tag-draft')} color={(toUpper(text) === STATUS.ACTIVE) ? '#E2FFEA' : '#F3F3F3'}>{(toUpper(text) === STATUS.INPROGRESS) ? upperFirst(toLower('Draft')):upperFirst(toLower(text))}</Tag>
        },
        {
            title: <div className='font-family-weight-500 fs10 lh18 text-upper'>{containerConstants.formatString(containerConstants.LINKED_PARTIES)}</div>,
            dataIndex: DATA_INDEX.PARTY_CODE,
            width: '20%',
            fixed: 'right',
            key: '5',
            render: (text, record, index) => <div className='font-family-weight-normal fs14 lh22' style = {{display: 'flex', alignItems: 'center', justifyContent: 'right'}}>
                                {record && record.partyCode && record.partyCode.split(",").length > 0 &&
                                 record.partyCode.split(",").length}
                                {record && record.partyCode
                                    &&
                                    getMenuForDropDown(record.partyCode)
                                }
                                <Button
                                ghost
                                style={{ border: '1px solid', borderRadius: '4px' }}
                                type="primary"
                                onClick={ (text)=>openLinkTemplateBox(record)}
                                >
                                    {containerConstants.formatString(containerConstants.LINK_PARTIES)}
                                </Button>
                            </div>
        },
    ];

    const handleSearch = (selectedKeys, confirm, dataIndex) => {
        // Object.keys(allPartyNameWithMasterCodeMaps).map((key)=>{
        //   if(key.toLowerCase().includes(searchfilters[dataIndex].toLowerCase())){
        //     partycodes = partycodes === '' ? allPartyNameWithMasterCodeMaps[key] : partycodes + '&&##&&' + allPartyNameWithMasterCodeMaps[key];
        //   }
        // });
        // setEmptySearchResult(true);
        setShowTable(true);
        getAllTemplate( );
    };

    const handleReset = ( dataIndex ) => {
        setSearchfilters( '' );
        setShowTable(true);
        getAllTemplate();
    };

    return (
        <div style ={{height: '100%'}}>
            {console.log(labelTemplateList)}
            <LabelTemplateStyle/>
            {partyMasterCodeSet && partyMasterCodeSet.size> 0 &&<Modal
                title={containerConstants.formatString(containerConstants.LINK_PARTIES)}
                visible={showModalDialogLinkParty}
                style = {{width: '406px !important', height: '175px', borderRadius: '4px'}}
                footer={[
                    <Button key="cancel" style={{ color: '#727272', border: 0 }} onClick={closeLinkPartyDialog}>
                        {containerConstants.formatString(containerConstants.CANCEL)}
                    </Button>,
                    <Button loading = {showLoading} key="submit" type="primary"  onClick={saveLinkedParty}>
                        {containerConstants.formatString(containerConstants.DONE)}
                    </Button>
                ]}
                onCancel={closeLinkPartyDialog}
            >
                <Row style = {{justifyContent: 'center'}}>
                    <Col span={6}>{containerConstants.formatString(containerConstants.NAME)}</Col>
                    <Col span={18}>
                        <Select
                            mode="multiple"
                            allowClear
                            showArrow= {true}
                            style = {{display: 'block'}}
                            onChange={value => {
                                if (value) {
                                    setLinkedPartyCodes(value);
                                }
                            }}
                            placeholder={containerConstants.formatString(containerConstants.SELECT)}
                            value={linkedPartyCodes}
                            options = {avaliablePartyMasterCodeOptios}
                        >
                        </Select>

                    </Col>
                </Row>
            </Modal>}
            {!showEditor.visible
                && <BreadCrumb
                urlList={ store.fromNewSetting ? urlListForNewSetting : urlList}
                rightItem={showTable ?
                            <Button
                                disabled = { store.fromFCR ? false : store.showCustom }
                                className='fw500'
                                style={{ display: 'flex', height: '24px', padding: '0 8px', borderRadius: '4px' }}
                                type="primary"
                                icon={<PlusOutlined style={{ display: 'flex', alignSelf: 'center', fontSize: '10px' }} />}
                                onClick={() => setShowModalDialog({
                                    visible: true,
                                    title: containerConstants.formatString(containerConstants.CHOOSE_TEMPLATE),
                                    modalType: TEMPLATE_MODAL_TYPE.CHOOSE_TEMPLATE
                                })}
                            >
                                {containerConstants.formatString(containerConstants.CREATE_TEMPLATE)}
                            </Button> : null}

            />}
            <Spin id ='label-template-spin' wrapperClassName = 'label-template-spin-height' spinning={showLoading}>
            {!showEditor.visible &&  <Card id='label-template' className='m16'
            style = {showTable ? {height: '100%', position: 'relative', zIndex:0}: {position: 'relative', zIndex:0}}
                bodyStyle={{  padding: '12px 16px', border: '1px solid #DDDDDD', boxSizing: 'border-box', borderRadius: '4px', background: '#FFFFFF', width: '100%', position: 'relative', height: showTable ? '100%' : 'auto' }}
            >
                {!showTable && searchfilters === '' ? <EmptyDataView {...{ setShowModalDialog }} /> :
                    <div id='label_template_table'>
                        <Table
                            components={{
                                body: {
                                    cell: CustomCell
                                }
                            }}
                            bordered={true}
                            size='middle'
                            columns={LABEL_TEMPLATE_TABLE_HEADER}
                            dataSource={labelTemplateList}
                            scroll={{ x: 900 }}
                            pagination={false}

                        />
                        <CustomPagination  pageDetail = { pageDetail} paginationDetails = {paginationDetails} handlePageChange = {handlePageChange} handlePgaeSizeChange  = {handlePgaeSizeChange} curentPageOption = {paginationDetails.pageSizeText}/>
                    </div>}
            </Card>}
            {showEditor.visible && <HtmlEditor {...{ showEditor, setShowEditor, setShowTable, updateTemplateStatus }} />}
            {!showEditor.visible && <CustomModal {...{ showModalDialog, setShowEditor, setShowModalDialog, showConfirmModalDialog, setShowConfirmModalDialog, deleteTemplate, updateTemplateStatus }} />}
            </Spin>
        </div>
    )
}

export default LabelTemplate
